"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[25677],{54407(i,e,n){n.r(e),n.d(e,{assets:()=>c,contentTitle:()=>r,default:()=>f,frontMatter:()=>o,metadata:()=>t,toc:()=>l});let t=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 7 Statement of Cash Flows/disclosure-of-changes-in-liabilities-8c638cacbf","title":"Disclosure of Changes in Liabilities Arising from Financing Activities (IAS 7)","description":"September 2019","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 7 Statement of Cash Flows/Disclosure of Changes in Liabilities Arising from Financing Activities (IAS 7).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 7 Statement of Cash Flows","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-7-statement-of-cash-flows-5c8f1f3849/disclosure-of-changes-in-liabilities-8c638cacbf","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-7-statement-of-cash-flows-5c8f1f3849/disclosure-of-changes-in-liabilities-8c638cacbf","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"id":"disclosure-of-changes-in-liabilities-8c638cacbf","title":"Disclosure of Changes in Liabilities Arising from Financing Activities (IAS 7)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-7-statement-of-cash-flows-5c8f1f3849/disclosure-of-changes-in-liabilities-8c638cacbf","sidebar_position":2},"sidebar":"knowledgeSidebar","previous":{"title":"Demand Deposits with Restrictions on Use arising from a Contract with a Third Party (IAS 7)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-7-statement-of-cash-flows-5c8f1f3849/demand-deposits-with-restrictions-on-d9379cfc70"},"next":{"title":"Liabilities in relation to a Joint Operator\u2019s Interest in a Joint Operation (IFRS 11)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-11-joint-arrangements-5488ddb2b3/liabilities-in-relation-to-a-joint-o-d61c19789d"}}');var a=n(74848),s=n(28453);let o={id:"disclosure-of-changes-in-liabilities-8c638cacbf",title:"Disclosure of Changes in Liabilities Arising from Financing Activities (IAS 7)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-7-statement-of-cash-flows-5c8f1f3849/disclosure-of-changes-in-liabilities-8c638cacbf",sidebar_position:2},r="Disclosure of Changes in Liabilities Arising from Financing Activities (IAS 7)",c={},l=[{value:"Meeting the disclosure objective (Paragraph 44A of IAS 7)",id:"meeting-the-disclosure-objective-paragraph-44a-of-ias-7",level:2},{value:"Reconciling between the opening and closing balances of liabilities arising from financing activities",id:"reconciling-between-the-opening-and-closing-balances-of-liabilities-arising-from-financing-activities",level:2}];function h(i){let e={h1:"h1",h2:"h2",header:"header",p:"p",...(0,s.R)(),...i.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(e.header,{children:(0,a.jsx)(e.h1,{id:"disclosure-of-changes-in-liabilities-arising-from-financing-activities-ias-7",children:"Disclosure of Changes in Liabilities Arising from Financing Activities (IAS 7)"})}),"\n",(0,a.jsx)(e.p,{children:"September 2019"}),"\n",(0,a.jsx)(e.p,{children:"The Committee received a request from users of financial statements (investors) about the disclosure requirements in IAS 7 that relate to changes in liabilities arising from financing activities. Specifically, investors asked whether the disclosure requirements in paragraphs 44B\u201344E of IAS 7 are adequate to require an entity to provide disclosures that meet the objective in paragraph 44A of IAS 7."}),"\n",(0,a.jsx)(e.h2,{id:"meeting-the-disclosure-objective-paragraph-44a-of-ias-7",children:"Meeting the disclosure objective (Paragraph 44A of IAS 7)"}),"\n",(0,a.jsx)(e.p,{children:"Paragraph 44A of IAS 7 requires an entity to provide \u2018disclosures that enable [investors] to evaluate changes in liabilities arising from financing activities, including both changes arising from cash flows and non-cash changes\u2019."}),"\n",(0,a.jsx)(e.p,{children:"To the extent necessary to satisfy the objective in paragraph 44A, paragraph 44B specifies that an entity discloses the following changes in liabilities arising from financing activities:"}),"\n",(0,a.jsx)(e.p,{children:"a. changes from financing cash flows;\nb. changes arising from obtaining or losing control of subsidiaries or other businesses;\nc. the effect of changes in foreign exchange rates;\nd. changes in fair values; and\ne. other changes."}),"\n",(0,a.jsx)(e.p,{children:"The Board explained in paragraph BC16 that it developed the disclosure objective in paragraph 44A to reflect the needs of investors, including those summarised in paragraph BC10. The Board also noted in paragraph BC18 that when considering whether it has fulfilled the objective in paragraph 44A, an entity takes into consideration the extent to which information about changes in liabilities arising from financing activities provides relevant information to investors, considering the needs of investors summarised in paragraph BC10. These investor needs are:"}),"\n",(0,a.jsx)(e.p,{children:"a. to check their understanding of the entity\u2019s cash flows and use that understanding to improve their confidence in forecasting the entity\u2019s future cash flows;\nb. to provide information about the entity\u2019s sources of finance and how those sources have been used over time; and\nc. to help them understand the entity\u2019s exposure to risks associated with financing"}),"\n",(0,a.jsx)(e.h2,{id:"reconciling-between-the-opening-and-closing-balances-of-liabilities-arising-from-financing-activities",children:"Reconciling between the opening and closing balances of liabilities arising from financing activities"}),"\n",(0,a.jsx)(e.p,{children:"Paragraph 44D of IAS 7 states that \u2018one way to fulfil the disclosure requirement in paragraph 44A is by providing a reconciliation between the opening and closing balances in the statement of financial position for liabilities arising from financing activities, including the changes identified in paragraph 44B\u2019."}),"\n",(0,a.jsx)(e.p,{children:"When an entity discloses such a reconciliation it provides information that enables investors to link items included in the reconciliation to other areas of the financial statements. In doing this, an entity applies:"}),"\n",(0,a.jsx)(e.p,{children:"a. paragraph 44C to identify liabilities arising from financing activities and use them as the basis of the reconciliation. Paragraph 44C defines these liabilities as \u2018liabilities for which cash flows were, or future cash flows will be, classified in the statement of cash flows as cash flows from financing activities\u2019. If an entity also chooses to define, and reconcile, a different \u2018net debt\u2019 measure, this does not remove the requirement for the entity to identify its liabilities arising from financing activities as defined in paragraph 44C.\nb. paragraph 44E to disclose changes in liabilities arising from financing activities separately from changes in any other assets and liabilities.\nc. paragraph 44D to provide sufficient information to enable investors to link the items included in the reconciliation to amounts reported in the statement of financial position and the statement of cash flows, or related notes. An entity develops disclosures that enable investors to link (i) the opening and closing balances of the liabilities arising from financing activities reported in the reconciliation, to (ii) amounts reported in the entity\u2019s statement of financial position (or related notes) regarding those liabilities."}),"\n",(0,a.jsx)(e.p,{children:"The Committee observed that an entity applies judgement in determining the extent to which it disaggregates and explains the changes in liabilities arising from financing activities included in the reconciliation to meet the objective in paragraph 44A. In this respect, the Committee noted the following:"}),"\n",(0,a.jsx)(e.p,{children:"a. in disaggregating liabilities arising from financing activities, and cash and non-cash changes in those liabilities, an entity applies paragraph 44B of IAS 7 and paragraph 30A of IAS 1 Presentation of Financial Statements. Paragraph 30A of IAS 1 states that an entity \u2018shall not reduce the understandability of its financial statements\u2026by aggregating material items that have different natures or functions\u2019. Accordingly, an entity discloses any individually material items separately in the reconciliation. Such items include material classes of liability (or asset) arising from financing activities and material reconciling items (ie cash or non-cash changes).\nb. in explaining liabilities arising from financing activities, and cash and non-cash changes in those liabilities, an entity applies paragraph 44B of IAS 7 and paragraph 112(c) of IAS 1. Paragraph 112(c) of IAS 1 requires an entity to disclose \u2018information that is not presented elsewhere in the financial statements, but is relevant to an understanding of any of them\u2019. Accordingly, applying paragraphs 44A\u201344E, an entity determines the appropriate structure for its reconciliation including the appropriate level of disaggregation. Thereafter, the entitydetermines whether additional explanation is needed to meet the disclosure objective in paragraph 44A. An entity would explain each class of liability (or asset) arising from financing activities included in the reconciliation and each reconciling item in a way that (i) provides information about its sources of finance, (ii) enables investors to check their understanding of the entity\u2019s cash flows, and (iii) enables investors to link items to the statement of financial position and the statement of cash flows, or related notes."}),"\n",(0,a.jsx)(e.p,{children:"Accordingly, the Committee concluded that the principles and requirements in IFRS Standards provide an adequate basis for an entity to disclose information about changes in liabilities arising from financing activities that enables investors to evaluate those changes. Accordingly, the Committee concluded that the disclosure requirements in paragraphs 44B\u201344E of IAS 7, together with requirements in IAS 1, are adequate to require an entity to provide disclosures that meet the objective in paragraph 44A of IAS 7. Consequently, the Committee decided not to add the matter to its standard-setting agenda."})]})}function f(i={}){let{wrapper:e}={...(0,s.R)(),...i.components};return e?(0,a.jsx)(e,{...i,children:(0,a.jsx)(h,{...i})}):h(i)}},28453(i,e,n){n.d(e,{R:()=>o,x:()=>r});var t=n(96540);let a={},s=t.createContext(a);function o(i){let e=t.useContext(s);return t.useMemo(function(){return"function"==typeof i?i(e):{...e,...i}},[e,i])}function r(i){let e;return e=i.disableParentContext?"function"==typeof i.components?i.components(a):i.components||a:o(i.components),t.createElement(s.Provider,{value:e},i.children)}}}]);